// ── PUT /api/users/profile ───────────────────────────────────────────────────
app.put('/api/users/profile', verifyToken, async (req, res) => {
  try {
    const { name, username, email, avatar_url, phone, bio, password, preferences } = req.body;
    const userId = req.user.sub;

    if (!name || !username || !email) {
      return res.status(400).json({ error: 'Name, username, and email are required.' });
    }

    const cleanUsername = username.trim().toLowerCase();
    const cleanEmail = email.trim().toLowerCase();

    if (cleanUsername.includes(' ')) {
      return res.status(400).json({ error: 'Username cannot contain spaces.' });
    }

    // Check if username is already taken by another user
    const existingUser = await sql`
      SELECT id FROM users 
      WHERE LOWER(username) = ${cleanUsername} AND id != ${userId}
    `;
    if (existingUser.length > 0) {
      return res.status(409).json({ error: 'Username is already taken.' });
    }

    // Check if email is already taken by another user
    const existingEmail = await sql`
      SELECT id FROM users 
      WHERE LOWER(email) = ${cleanEmail} AND id != ${userId}
    `;
    if (existingEmail.length > 0) {
      return res.status(409).json({ error: 'Email is already taken.' });
    }

    // Check if phone is already taken by another user
    if (phone && phone.trim()) {
      const cleanPhone = phone.trim();
      const existingPhone = await sql`
        SELECT id FROM users 
        WHERE phone = ${cleanPhone} AND id != ${userId}
      `;
      if (existingPhone.length > 0) {
        return res.status(409).json({ error: 'Phone number is already taken.' });
      }
    }

    let passwordHashUpdate = undefined;
    if (password && password.length >= 8) {
       const bcrypt = require('bcrypt');
       const salt = await bcrypt.genSalt(10);
       passwordHashUpdate = await bcrypt.hash(password, salt);
    }

    // Update user in DB
    let userRecord;
    if (passwordHashUpdate) {
      const rows = await sql`
        UPDATE users
        SET name = ${name.trim()},
            username = ${cleanUsername},
            email = ${cleanEmail},
            avatar_url = ${avatar_url ? avatar_url.trim() : null},
            phone = ${phone ? phone.trim() : null},
            bio = ${bio ? bio.trim() : null},
            preferences = ${preferences ? JSON.stringify(preferences) : '{}'}::jsonb,
            updated_at = NOW(),
            password_hash = ${passwordHashUpdate}
        WHERE id = ${userId}
        RETURNING *
      `;
      userRecord = rows[0];
    } else {
      const rows = await sql`
        UPDATE users
        SET name = ${name.trim()},
            username = ${cleanUsername},
            email = ${cleanEmail},
            avatar_url = ${avatar_url ? avatar_url.trim() : null},
            phone = ${phone ? phone.trim() : null},
            bio = ${bio ? bio.trim() : null},
            preferences = ${preferences ? JSON.stringify(preferences) : '{}'}::jsonb,
            updated_at = NOW()
        WHERE id = ${userId}
        RETURNING *
      `;
      userRecord = rows[0];
    }
    const user = userRecord;

    if (!user) {
      return res.status(404).json({ error: 'User not found in database. Please sign out and sign in again.' });
    }

    res.json({
      success: true,
      user: {
        id: user.id,
        name: user.name,
        username: user.username,
        email: user.email,
        avatar_url: user.avatar_url,
        phone: user.phone,
        bio: user.bio,
        is_verified: user.is_verified
      }
    });
  } catch (err) {
    console.error('Update profile error:', err);
    res.status(500).json({ error: 'Failed to update profile.' });
  }
});

