// ── GET /api/users/search ────────────────────────────────────────────────────
app.get('/api/users/search', verifyToken, async (req, res) => {
  try {
    const userId = req.user.sub;
    const { q } = req.query;
    if (!q || q.trim().length < 1) {
      return res.json({ users: [] });
    }
    const pattern = `%${q.trim().toLowerCase()}%`;

    let users = [];
    if (isInMemory) {
      users = inMemoryStore.users
        .filter(u => u.id !== userId &&
          ((u.username || '').toLowerCase().includes(q.trim().toLowerCase()) ||
            (u.name || '').toLowerCase().includes(q.trim().toLowerCase())))
        .slice(0, 10)
        .map(u => ({
          id: u.id,
          name: u.name,
          username: u.username,
          avatar_url: u.avatar_url,
          bio: u.bio
        }));
    } else {
      users = await sql`
        SELECT id, name, username, avatar_url, bio, preferences
        FROM users
        WHERE id != ${userId}
          AND (LOWER(username) ILIKE ${pattern} OR LOWER(name) ILIKE ${pattern})
        LIMIT 10
      `;
    }

    // Query friendships for this user to determine status
    let friendships = [];
    if (isInMemory) {
      friendships = inMemoryStore.friendships.filter(
        f => f.user_id_1 === userId || f.user_id_2 === userId
      );
    } else {
      friendships = await sql`
        SELECT user_id_1, user_id_2, status, sender_id
        FROM friendships
        WHERE user_id_1 = ${userId} OR user_id_2 = ${userId}
      `;
    }

    const fsMap = new Map();
    friendships.forEach(f => {
      const otherId = f.user_id_1 === userId ? f.user_id_2 : f.user_id_1;
      let status = 'none';
      if (f.status === 'accepted') {
        status = 'accepted';
      } else if (f.status === 'pending') {
        status = f.sender_id === userId ? 'pending_sent' : 'pending_received';
      }
      fsMap.set(otherId, status);
    });

    const enriched = users.map(u => {
      const localData = readUserData(u.username);
      const userBooks = localData.books || null;
      const isPublic = u.preferences?.privacy?.profilePublic !== false;
      return {
        id: u.id,
        name: u.name,
        username: u.username,
        avatar_url: u.avatar_url,
        bio: isPublic ? u.bio : null,
        friendship_status: fsMap.get(u.id) || 'none',
        currentBook: isPublic && userBooks && userBooks.title ? {
          title: userBooks.title,
          author: userBooks.author,
          currentPage: userBooks.currentPage || userBooks.current_page,
          totalPages: userBooks.totalPages || userBooks.total_pages
        } : null
      };
    });

    res.json({ users: enriched });
  } catch (err) {
    console.error('User search error:', err);
    res.status(500).json({ error: 'Failed to search users.' });
  }
});

