import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Search, Send, ArrowLeft, BookOpen, Trash2, Users, MessageSquare, Image, X, MoreVertical, BookUser, MessageCircle, ExternalLink, Download } from 'lucide-react';
import Avatar from './Avatar';

// ─── Helpers ─────────────────────────────────────────────────────────────────
function formatTime(dateVal) {
  if (!dateVal) return '';
  const d = new Date(dateVal);
  if (isNaN(d.getTime())) return '';
  const now = new Date();
  const diff = now - d;
  if (diff < 60000) return 'just now';
  if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
  if (diff < 86400000) return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  if (diff < 604800000) return d.toLocaleDateString([], { weekday: 'short' }) + ' ' + d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  return d.toLocaleDateString([], { month: 'short', day: 'numeric' });
}

function useDebounce(value, delay) {
  const [dv, setDv] = useState(value);
  useEffect(() => {
    const t = setTimeout(() => setDv(value), delay);
    return () => clearTimeout(t);
  }, [value, delay]);
  return dv;
}

// Fetch with timeout
async function fetchWithTimeout(url, options = {}, timeoutMs = 8000) {
  const controller = new AbortController();
  const id = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const res = await fetch(url, { ...options, signal: controller.signal });
    return res;
  } finally {
    clearTimeout(id);
  }
}

// Compress image before sending to avoid payload limits and speed up transfers
function compressImage(base64Str, maxWidth = 1000, maxHeight = 1000) {
  return new Promise((resolve) => {
    const img = new window.Image();
    img.src = base64Str;
    img.onload = () => {
      let width = img.width;
      let height = img.height;
      if (width > height) {
        if (width > maxWidth) {
          height = Math.round((height * maxWidth) / width);
          width = maxWidth;
        }
      } else {
        if (height > maxHeight) {
          width = Math.round((width * maxHeight) / height);
          height = maxHeight;
        }
      }
      const canvas = document.createElement('canvas');
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(img, 0, 0, width, height);
      resolve(canvas.toDataURL('image/jpeg', 0.7));
    };
    img.onerror = () => resolve(base64Str);
  });
}

// Format text to make links clickable
function formatMessageText(text, isSelectMode) {
  if (!text) return '';
  const urlRegex = /(https?:\/\/[^\s]+)/g;
  const parts = text.split(urlRegex);
  return parts.map((part, index) => {
    if (part.startsWith('http://') || part.startsWith('https://')) {
      return (
        <a
          key={index}
          href={part}
          target="_blank"
          rel="noopener noreferrer"
          style={{
            color: 'inherit',
            textDecoration: 'underline',
            wordBreak: 'break-all',
            fontWeight: '600'
          }}
          onClick={e => {
            if (isSelectMode) {
              e.preventDefault();
            } else {
              e.stopPropagation();
            }
          }}
        >
          {part}
        </a>
      );
    }
    return part;
  });
}

function hasEmbed(text) {
  if (!text) return false;
  const imageRegex = /\.(jpeg|jpg|gif|png|webp)($|\?)/i;
  const pinterestRegex = /pinterest\.com\/pin\/(\d+)/i;
  return imageRegex.test(text) || pinterestRegex.test(text);
}

function renderParsedEmbedsOnly(text, isSelectMode, setActiveImageUrl) {
  if (!text) return null;
  const urlRegex = /(https?:\/\/[^\s]+)/g;
  const parts = text.split(urlRegex);

  const imageRegex = /\.(jpeg|jpg|gif|png|webp)($|\?)/i;
  const pinterestRegex = /pinterest\.com\/pin\/(\d+)/i;

  let embeds = [];

  parts.forEach((part, index) => {
    if (part.startsWith('http://') || part.startsWith('https://')) {
      // Check for image embed
      if (imageRegex.test(part)) {
        embeds.push(
          <div key={`img-${index}`} style={{ marginTop: index > 0 ? '6px' : '0' }}>
            <img
              src={part}
              alt="Shared media"
              style={{
                maxWidth: '100%',
                maxHeight: '260px',
                borderRadius: '12px',
                display: 'block',
                cursor: isSelectMode ? 'pointer' : 'zoom-in'
              }}
              onClick={e => {
                if (isSelectMode) return;
                e.stopPropagation();
                if (setActiveImageUrl) {
                  setActiveImageUrl(part);
                } else {
                  window.open(part, '_blank');
                }
              }}
            />
          </div>
        );
      }

      // Check for Pinterest embed
      const pinMatch = part.match(pinterestRegex);
      if (pinMatch && pinMatch[1]) {
        const pinId = pinMatch[1];
        embeds.push(
          <div key={`pin-${index}`} style={{ marginTop: index > 0 ? '6px' : '0' }}>
            <iframe
              src={`https://assets.pinterest.com/ext/embed.html?id=${pinId}`}
              height="280"
              width="240"
              frameBorder="0"
              scrolling="no"
              style={{
                border: 'none',
                borderRadius: '12px',
                display: 'block',
                background: 'transparent',
                boxShadow: 'none'
              }}
            />
          </div>
        );
      }
    }
  });

  return embeds.length > 0 ? <div>{embeds}</div> : null;
}




// ─── Chat Conversation View ───────────────────────────────────────────────────
function ChatView({ friend, currentUser, token, onBack }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [sending, setSending] = useState(false);

  // Extract true user ID from token to perfectly identify own messages
  const tokenUserId = React.useMemo(() => {
    try {
      if (!token) return currentUser?.id;
      return JSON.parse(atob(token.split('.')[1])).sub || currentUser?.id;
    } catch {
      return currentUser?.id;
    }
  }, [token, currentUser]);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);
  const [activeImageUrl, setActiveImageUrl] = useState(null);

  // Clear drafting state when switching users or friends
  useEffect(() => {
  // eslint-disable-next-line react-hooks/set-state-in-effect
    setImagePreview(null);
    setInput('');
    setError(null);
    setActiveImageUrl(null);
  }, [currentUser?.id, friend?.id]);

  // Message selection states
  const [isSelectMode, setIsSelectMode] = useState(false);
  const [selectedMsgIds, setSelectedMsgIds] = useState([]);
  const [showMenu, setShowMenu] = useState(false);

  const endRef = useRef(null);
  const chatContainerRef = useRef(null);
  const inputRef = useRef(null);
  const fileInputRef = useRef(null);
  const pollRef = useRef(null);
  const menuRef = useRef(null);

  // eslint-disable-next-line react-hooks/preserve-manual-memoization
  const fetchMessages = useCallback(async (isInitial = false) => {
    if (!token || !friend?.id) {
      setLoading(false);
      return;
    }
    try {
      const res = await fetchWithTimeout(`/api/chat/${friend.id}`, {
        headers: { Authorization: `Bearer ${token}` }
      }, 10000);

      if (res.ok) {
        const data = await res.json();
        setMessages(data.messages || []);
        setError(null);
      } else {
        const errData = await res.json().catch(() => ({}));
        if (isInitial) setError(errData.error || 'Could not load messages.');
      }
    } catch (e) {
      if (e.name === 'AbortError') {
        if (isInitial) setError('Request timed out. Check your connection.');
      } else if (isInitial) {
        setError('Network error. Please try again.');
      }
    } finally {
      if (isInitial) setLoading(false);
    }
  }, [token, friend?.id]);

  useEffect(() => {
  // eslint-disable-next-line react-hooks/set-state-in-effect
    setLoading(true);
    setError(null);
    setMessages([]);
    setImagePreview(null);
    setIsSelectMode(false);
    setSelectedMsgIds([]);
    fetchMessages(true);

    pollRef.current = setInterval(() => fetchMessages(false), 4000);
    return () => clearInterval(pollRef.current);
  }, [fetchMessages]);

  // Scroll to bottom on initial load of friend chat
  useEffect(() => {
    if (friend?.id) {
      const scroll = () => {
        if (chatContainerRef.current) {
          chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
        }
      };
      scroll();
      const t1 = setTimeout(scroll, 100);
      const t2 = setTimeout(scroll, 500);
      const t3 = setTimeout(scroll, 1200);
      return () => {
        clearTimeout(t1);
        clearTimeout(t2);
        clearTimeout(t3);
      };
    }
  }, [friend?.id]);

  // Scroll to bottom when new messages are added, but only if user was already at bottom or sent it
  const prevMessagesLengthRef = useRef(0);
  useEffect(() => {
    if (!friend?.id || messages.length === 0) {
      prevMessagesLengthRef.current = 0;
      return;
    }

    const prevLength = prevMessagesLengthRef.current;
    prevMessagesLengthRef.current = messages.length;

    if (prevLength > 0 && messages.length > prevLength) {
      const container = chatContainerRef.current;
      if (container) {
        const lastMsg = messages[messages.length - 1];
        const isSelf = String(lastMsg.senderId) === String(tokenUserId);

        // If the user is already near the bottom (within 120px) or they sent the message, scroll to bottom
        const isNearBottom = container.scrollHeight - container.scrollTop - container.clientHeight < 120;
        if (isSelf || isNearBottom) {
          container.scrollTo({
            top: container.scrollHeight,
            behavior: 'smooth'
          });
        }
      }
    }
  }, [messages, friend?.id, tokenUserId]);

  useEffect(() => {
    setTimeout(() => inputRef.current?.focus(), 100);
  }, [friend?.id]);

  // Handle clicking outside 3-dot dropdown to close it
  useEffect(() => {
    const handleOutsideClick = (e) => {
      if (showMenu && menuRef.current && !menuRef.current.contains(e.target)) {
        setShowMenu(false);
      }
    };
    document.addEventListener('mousedown', handleOutsideClick);
    return () => document.removeEventListener('mousedown', handleOutsideClick);
  }, [showMenu]);

  // Message context menu trigger hook
  const [activeMsgMenuId, setActiveMsgMenuId] = useState(null);

  useEffect(() => {
    const closeMsgMenu = () => setActiveMsgMenuId(null);
    document.addEventListener('click', closeMsgMenu);
    return () => document.removeEventListener('click', closeMsgMenu);
  }, []);

  const handleFileSelect = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith('image/')) {
      alert('Please select an image file.');
      return;
    }

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        // Compress image client side down to safe dimensions and size
        const compressed = await compressImage(reader.result);
        setImagePreview(compressed);
      } catch (err) {
        console.error('Image compression failed, using original:', err);
        setImagePreview(reader.result);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleSend = async (e) => {
    e.preventDefault();
    const text = input.trim();
    const image = imagePreview;

    if ((!text && !image) || sending || !token) return;

    setInput('');
    setImagePreview(null);
    setSending(true);

    // Optimistic update
    const tempId = `opt-${Date.now()}`;
    const optimistic = {
      id: tempId,
      senderId: tokenUserId,
      text,
      imageUrl: image,
      createdAt: new Date().toISOString(),
      optimistic: true
    };
    setMessages(prev => [...prev, optimistic]);

    try {
      const res = await fetchWithTimeout('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ receiverId: friend.id, messageText: text, imageUrl: image })
      }, 15000);

      if (res.ok) {
        const data = await res.json();
        setMessages(prev => prev.map(m => m.id === tempId ? (data.message || { ...m, optimistic: false }) : m));
        setError(null);
      } else {
        setMessages(prev => prev.filter(m => m.id !== tempId));
        const errData = await res.json().catch(() => ({}));
        setError(errData.error || 'Failed to send.');
        setTimeout(() => setError(null), 4000);
      }
    } catch {
      setMessages(prev => prev.filter(m => m.id !== tempId));
      setError('Send failed. Check your connection.');
      setTimeout(() => setError(null), 4000);
    } finally {
      setSending(false);
    }
  };

  const handleDelete = async (msgId) => {
    if (!window.confirm('Delete this message?')) return;
    setMessages(prev => prev.filter(m => m.id !== msgId));
    try {
      await fetchWithTimeout(`/api/chat/message/${msgId}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${token}` }
      });
  // eslint-disable-next-line no-empty
    } catch { }
  };

  const handleDeleteSelected = async () => {
    if (selectedMsgIds.length === 0) return;
    if (!window.confirm(`Delete the ${selectedMsgIds.length} selected message(s)?`)) return;

    setMessages(prev => prev.filter(m => !selectedMsgIds.includes(m.id)));
    const ids = [...selectedMsgIds];
    setSelectedMsgIds([]);
    setIsSelectMode(false);

    try {
      await Promise.all(ids.map(id =>
        fetchWithTimeout(`/api/chat/message/${id}`, {
          method: 'DELETE',
          headers: { Authorization: `Bearer ${token}` }
        }, 8000)
      ));
    } catch (e) {
      console.error(e);
    }
  };

  const handleClearChat = async () => {
    if (!window.confirm('Clear all messages in this conversation? This cannot be undone.')) return;
    setMessages([]);
    setShowMenu(false);
    try {
      const ids = messages.map(m => m.id);
      await Promise.all(ids.map(id =>
        fetchWithTimeout(`/api/chat/message/${id}`, {
          method: 'DELETE',
          headers: { Authorization: `Bearer ${token}` }
        }, 8000)
      ));
    } catch (e) {
      console.error(e);
    }
  };

  const friendName = friend?.name || friend?.username || 'Reader';
  const currentBook = friend?.currentBook;

  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      height: '100%',
      background: 'var(--option-bg, #f7f3e9)',
      position: 'relative'
    }}>
      {/* Chat Header */}
      <div style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: '16px 24px',
        borderBottom: '1px solid var(--border-color)',
        background: 'var(--surface-bg)',
        flexShrink: 0,
        boxShadow: '0 2px 10px rgba(0,0,0,0.03)',
        zIndex: 10,
        position: 'relative'
      }}>
        {isSelectMode ? (
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', width: '100%' }}>
            <span style={{ fontSize: '14px', fontWeight: '800', color: 'var(--ink)' }}>
              Selected {selectedMsgIds.length} {selectedMsgIds.length === 1 ? 'message' : 'messages'}
            </span>
            <div style={{ display: 'flex', gap: '8px' }}>
              <button
                onClick={handleDeleteSelected}
                disabled={selectedMsgIds.length === 0}
                style={{
                  display: 'flex', alignItems: 'center', gap: '6px',
                  padding: '8px 16px', background: selectedMsgIds.length > 0 ? 'var(--danger-color, #d94a43)' : 'rgba(0,0,0,0.06)',
                  color: selectedMsgIds.length > 0 ? '#fff' : 'var(--text-secondary)', border: 'none', borderRadius: '18px',
                  fontSize: '12px', fontWeight: '700', cursor: selectedMsgIds.length > 0 ? 'pointer' : 'not-allowed',
                  transition: 'all 0.2s'
                }}
              >
                <Trash2 size={13} /> Delete
              </button>
              <button
                onClick={() => {
                  setIsSelectMode(false);
                  setSelectedMsgIds([]);
                }}
                style={{
                  padding: '8px 16px', background: 'transparent',
                  border: '1.5px solid var(--border-color)', borderRadius: '18px',
                  fontSize: '12px', color: 'var(--text-secondary)', cursor: 'pointer',
                  fontWeight: '600'
                }}
              >
                Cancel
              </button>
            </div>
          </div>
        ) : (
          <>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flex: 1, minWidth: 0 }}>
              {/* Back button for mobile view */}
              <button
                className="chat-back-btn"
                onClick={onBack}
                style={{
                  background: 'none', border: 'none', cursor: 'pointer', padding: '8px',
                  borderRadius: '50%', color: 'var(--ink)', display: 'none',
                  alignItems: 'center', transition: 'background 0.2s', marginRight: '4px'
                }}
                onMouseEnter={e => e.currentTarget.style.background = 'rgba(0,0,0,0.06)'}
                onMouseLeave={e => e.currentTarget.style.background = 'none'}
              >
                <ArrowLeft size={20} />
              </button>

              <Avatar user={friend} size={42} />

              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontWeight: '800', fontSize: '15px', color: 'var(--ink)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                  {friendName}
                </div>
                <div style={{ fontSize: '11px', color: 'var(--brass)', display: 'flex', alignItems: 'center', gap: '6px' }}>
                  <span>@{friend.username}</span>
                  {currentBook && (
                    <>
