                      fontFamily: 'var(--font-sans)', transition: 'background 0.15s'
                    }}
                    onMouseEnter={e => e.currentTarget.style.background = 'rgba(217,74,67,0.05)'}
                    onMouseLeave={e => e.currentTarget.style.background = 'none'}
                  >
                    Clear Chat
                  </button>
                </div>
              )}
            </div>
          </>
        )}
      </div>

      {/* Messages Area */}
      <div
