      radial-gradient(circle at bottom left, rgba(99, 102, 241, 0.08), transparent 40%),
      linear-gradient(180deg, #fffdf8 0%, #fcfaf4 100%)
    `,
          borderLeft: '1px solid rgba(0,0,0,0.06)',
          boxShadow: 'inset 0 1px 0 rgba(255,255,255,0.7)',
