                          padding: (m.text && /pinterest\.com\/pin\/(\d+)/i.test(m.text)) ? '0px' : '8px',
                          maxWidth: '260px',
                          cursor: isSelectMode ? 'pointer' : 'default',
                          position: 'relative',
                          marginTop: m.text ? '4px' : '0'
