                      >
                        {m.imageUrl && (
                          <div style={{ position: 'relative', overflow: 'hidden', borderRadius: '8px' }}>
                            <a
                              href={m.imageUrl}
                              target="_blank"
                              rel="noreferrer"
                              style={{ display: 'block', outline: 'none', cursor: isSelectMode ? 'pointer' : 'zoom-in' }}
